#include <iostream> using namespace std;int add(int a, int b) { return a + b; }int main() { int x = 5, y = 10; int result; bool isPositive = true; result = x * y - 3; if (result > 0) { isPositive = true; } else { isPositive = false; } for (int i = 0; i < 3; i++) { cout << i << " "; } cout << endl; int j = 0; while (j < 2) { j++; } if (x < y && isPositive) { result = add(x, y); } return 0; }